/**
 * Seed script — populates MongoDB with real project data fetched from Monday.com via MCP.
 * Run with: npx tsx scripts/seedFromMonday.ts
 *
 * Data sources:
 *   - MA-004 (7321609006): project name, number, status, budget hours
 *   - MA-003 (8874793711): team members (BIM/MEP/Modeller), ACC URL
 *   - ma003lookup.json:    pre-extracted MA-003 data (generated by MCP session)
 */

import path from 'path'
import fs from 'fs'
import mongoose from 'mongoose'

// ── Env ────────────────────────────────────────────────────────────────────

const MONGODB_URI = process.env.MONGODB_URI
if (!MONGODB_URI) { console.error('MONGODB_URI not set'); process.exit(1) }

const MA004_BOARD_ID  = '7321609006'
const MA004_BOARD_URL = 'https://easybim-company.monday.com/boards/7321609006'

// ── Status mapping ─────────────────────────────────────────────────────────

type ProjectStatus = 'Working on it' | 'On Hold' | 'Not Started' | 'Done' | 'Stuck'

function mapStatus(raw: string): ProjectStatus | null {
  if (raw === 'Working on it')              return 'Working on it'
  if (raw === 'On Hold')                    return 'On Hold'
  if (raw === 'Not Started')                return 'Not Started'
  if (raw === 'Finished' || raw === 'DONE') return 'Done'
  if (raw === 'Stuck' || raw === 'Declined') return 'Stuck'
  return null
}

