// ── Load MA-003 lookup ─────────────────────────────────────────────────────

interface MA003Data { bimMgr: string; mep: string; modeller: string; accUrl: string }
const lookupPath = path.join(__dirname, '..', 'lib', 'ma003lookup.json')
const ma003Lookup: Record<string, MA003Data> = JSON.parse(fs.readFileSync(lookupPath, 'utf-8'))

function parseAccId(url: string): string | undefined {
  const m = url.match(/\/projects?\/([\w-]{8,})/)
  return m?.[1]
}

function toMember(name: string, mondayId?: string) {
  if (!name) return undefined
  return { name, mondayId: mondayId ?? undefined }
}

// ── Mongoose model (inline to avoid circular deps) ─────────────────────────

const SnapshotSchema = new mongoose.Schema({
  status:            { type: String, enum: ['Working on it','On Hold','Not Started','Done','Stuck'], default: null },
  milestoneProgress: { type: Number, default: null },
  hoursProgress:     { type: Number, default: null },
  budgetHours:       { type: Number, default: null },
  actualHours:       { type: Number, default: null },
  bimManager:        { type: Object, default: null },
  mepCoordinator:    { type: Object, default: null },
  bimModeller:       { type: Object, default: null },
  openIssuesCount:   { type: Number, default: null },
  accModelStatus:    { type: String, default: null },
  lastSyncedAt:      { type: Date,   default: null },
  syncStatus:        { type: String, default: 'ok' },
  mondayLastSyncedAt:{ type: Date,   default: null },
  sheetsLastSyncedAt:{ type: Date,   default: null },
  accLastSyncedAt:   { type: Date,   default: null },
}, { _id: false })

const ProjectSchema = new mongoose.Schema({
  projectName:   { type: String, required: true },
  projectNumber: { type: String, required: true },
  externalIds:   { type: Object, required: true },
  snapshot:      { type: SnapshotSchema, default: () => ({}) },
  isActive:      { type: Boolean, default: true },
  displayOrder:  Number,
}, { timestamps: true })

ProjectSchema.index({ projectNumber: 1 }, { unique: true })

const Project = mongoose.models.Project ?? mongoose.model('Project', ProjectSchema)

// ── Seed ───────────────────────────────────────────────────────────────────

async function seed() {
  await mongoose.connect(MONGODB_URI!)
  console.log('Connected to MongoDB')

  const now = new Date()
  let upserted = 0
  let errors   = 0

  for (let i = 0; i < MA004_PROJECTS.length; i++) {
    const p = MA004_PROJECTS[i]
    const ma003 = p.ma003Id ? (ma003Lookup[p.ma003Id] ?? null) : null
    const accUrl  = ma003?.accUrl || ''
    const accId   = accUrl ? parseAccId(accUrl) : undefined

    const snapshot = {
      status:             mapStatus(p.rawStatus),
      milestoneProgress:  null,
      hoursProgress:      null,   // TS-001 hours: will be added in Phase 3 sync
      budgetHours:        p.budget > 0 ? Math.round(p.budget * 100) / 100 : null,
      actualHours:        null,
      bimManager:         toMember(ma003?.bimMgr ?? ''),
      mepCoordinator:     toMember(ma003?.mep ?? ''),
      bimModeller:        toMember(ma003?.modeller ?? ''),
      openIssuesCount:    null,
      accModelStatus:     null,
      lastSyncedAt:       now,
      syncStatus:         'ok' as const,
      mondayLastSyncedAt: now,
      sheetsLastSyncedAt: null,
      accLastSyncedAt:    null,
    }

    const externalIds = {
      mondayBoardId:  MA004_BOARD_ID,
      mondayBoardUrl: MA004_BOARD_URL,
      mondayItemId:   p.ma004Id,
      ma003ItemId:    p.ma003Id ?? undefined,
      accProjectId:   accId,
      accProjectUrl:  accUrl || undefined,
    }

    try {
      await Project.findOneAndUpdate(
        { projectNumber: p.num },
        { $set: { projectName: p.name, isActive: true, externalIds, snapshot, displayOrder: i + 1 } },
        { upsert: true, new: true, runValidators: false }
      )
      upserted++
      process.stdout.write(`\r${upserted}/${MA004_PROJECTS.length} upserted`)
    } catch (err) {
      errors++
      console.error(`\nError on ${p.num}:`, err instanceof Error ? err.message : err)
    }
  }

  console.log(`\nDone. ${upserted} upserted, ${errors} errors.`)
  await mongoose.disconnect()
}

seed().catch(err => { console.error(err); process.exit(1) })
